fn insert_sorted(v: i64, arr: i64, n: i64) -> i64
    pre n >= 0
    post ret == n + 1
= {
    // Find insertion position: first index where arr[i] >= v
    let mut pos = n;
    let mut i = 0;
    while i < n {
        if vec_get(arr, i) >= v {
            pos = i;
            break
        };
        i = i + 1
    };

    // Shift elements from pos to n-1 one position to the right
    let mut j = n - 1;
    while j >= pos {
        let _s = vec_set(arr, j + 1, vec_get(arr, j));
        j = j - 1
    };

    // Insert value at pos
    let _s = vec_set(arr, pos, v);

    // Return new length
